const crypto = require('crypto');
function id(q) { return 'card-' + crypto.createHash('sha256').update(q.trim().toLowerCase()).digest('hex').slice(0,12); }
const cards = [];
function add(topicId, question, answer, explanation, difficulty, bloomLevel, tags) {
  cards.push({ id: id(question), question, answer, explanation, difficulty, bloomLevel, tags, topicId });
}

// ENDOCRINOLOGY - endo-thyroid (15)
add('endo-thyroid','A 35-year-old woman presents with weight loss, palpitations, heat intolerance, tremor, and exophthalmos. TSH is undetectable, free T4 is elevated. Diagnosis and management?','Graves disease (most common cause of hyperthyroidism); treat with antithyroid drugs (methimazole first-line), radioactive iodine ablation, or thyroidectomy','CTS thyroid guidelines recommend methimazole (preferred) over PTU for Graves hyperthyroidism (except in first trimester pregnancy and thyroid storm). Beta-blockers (propranolol) provide symptomatic relief. Ophthalmopathy managed separately with steroids/surgery.',4,'apply',['Graves disease','hyperthyroidism','methimazole','exophthalmos','endocrinology']);
add('endo-thyroid','What are the signs and symptoms of hypothyroidism?','Fatigue, cold intolerance, weight gain, constipation, dry skin, hair loss, bradycardia, delayed relaxation of deep tendon reflexes, goiter, myxedema in severe cases','Most common cause in Canada: Hashimoto thyroiditis (autoimmune). Diagnosis: elevated TSH, low free T4. Treatment: levothyroxine (T4) — start low in elderly/cardiac disease (25 mcg), titrate to TSH 0.5-2.5 mIU/L.',2,'recall',['hypothyroidism','Hashimoto','levothyroxine','TSH','endocrinology']);
add('endo-thyroid','What is subclinical hypothyroidism and when should it be treated?','Elevated TSH (4.5-10 mIU/L) with normal free T4 and no symptoms; treat when: TSH >10, symptoms present, pregnancy planned or ongoing, strong family history or positive TPO antibodies','CTS guidelines recommend treating subclinical hypothyroidism when TSH >10 mIU/L or with symptoms. In asymptomatic patients with TSH 5-10, treat if TPO antibodies positive (higher progression risk). Annual monitoring if not treated.',3,'apply',['subclinical hypothyroidism','TSH','levothyroxine','TPO antibodies','endocrinology']);
add('endo-thyroid','A 60-year-old with known thyroid disease presents with confusion, hypothermia, bradycardia, and hypoventilation. Labs show TSH >100, T4 undetectable. Diagnosis and treatment?','Myxedema coma (severe hypothyroidism); treat with IV levothyroxine (300-500 mcg loading, then 50-100 mcg daily), IV T3 in critical illness, stress-dose steroids (hydrocortisone), supportive care','Myxedema coma has ~30-60% mortality. Precipitants: infection, cold exposure, surgery, medications (amiodarone, lithium). IV steroids given because of possible coexisting secondary adrenal insufficiency. Slow external rewarming.',5,'analyze',['myxedema coma','hypothyroidism','IV levothyroxine','endocrinology']);
add('endo-thyroid','What is thyroid storm and how is it managed?','Thyroid storm: life-threatening exaggerated hyperthyroidism (Burch-Wartofsky score ≥45); treat with PTU (blocks T4 to T3 conversion) + potassium iodide (1h after PTU), beta-blockers, IV corticosteroids, ICU care','Precipitants of thyroid storm: surgery, infection, radioiodine, trauma. PTU is preferred over methimazole in thyroid storm due to additional inhibition of peripheral T4→T3 conversion. Lugol iodine given 1h after PTU to prevent thyroid hormone synthesis from iodine.',5,'analyze',['thyroid storm','PTU','Lugol iodine','hyperthyroidism emergency','endocrinology']);
add('endo-thyroid','What is the approach to a thyroid nodule found on imaging?','Ultrasound evaluation → TIRADS classification; FNA (fine needle aspiration) if ≥1 cm with suspicious features or ≥1.5-2 cm regardless of features','CTS/ACR-TIRADS guidelines recommend biopsy based on nodule size and ultrasound features: hypoechoic, irregular margins, taller-than-wide, calcifications, extrathyroidal extension. Bethesda cytology classification guides management.',3,'apply',['thyroid nodule','TIRADS','FNA','ultrasound','endocrinology']);
add('endo-thyroid','What are the Bethesda categories for thyroid FNA and their malignancy risk?','I: non-diagnostic (repeat); II: benign (1-3%); III: atypia of undetermined significance (5-15%); IV: follicular neoplasm (15-30%); V: suspicious for malignancy (60-75%); VI: malignant (97-99%)','Bethesda III typically requires repeat FNA or molecular testing. Bethesda IV — lobectomy or molecular testing. Bethesda V/VI — thyroidectomy. Papillary thyroid carcinoma is most common thyroid cancer and has excellent prognosis.',3,'recall',['Bethesda classification','thyroid FNA','thyroid cancer','malignancy risk','endocrinology']);
add('endo-thyroid','What is Hashimoto thyroiditis and how is it diagnosed?','Autoimmune thyroiditis (most common cause of hypothyroidism in developed countries); elevated anti-TPO antibodies, elevated TSH, possibly goiter; treat with levothyroxine when hypothyroid','Hashimoto thyroiditis has female predominance (7:1). Lymphocytic infiltration and germinal center formation on histology. Most patients progress to hypothyroidism over years. Associated with other autoimmune diseases (T1DM, vitiligo, pernicious anemia, SLE).',2,'recall',['Hashimoto thyroiditis','TPO antibodies','hypothyroidism','autoimmune','endocrinology']);
add('endo-thyroid','A 28-year-old woman is 10 weeks pregnant with TSH 0.1 mIU/L and free T4 normal. What is the likely diagnosis?','Gestational hyperthyroidism — transient, caused by hCG stimulating TSH receptors; usually self-limiting and does not require antithyroid drugs','hCG shares alpha-subunit with TSH and cross-stimulates the TSH receptor. Gestational hyperthyroidism is most common in the first trimester, peaks with hCG. Hyperemesis gravidarum is associated. If free T4 elevated and symptomatic, consider methimazole (after 10 weeks — PTU in first trimester due to methimazole embryopathy).',4,'analyze',['gestational hyperthyroidism','hCG','pregnancy','PTU','methimazole','endocrinology']);
add('endo-thyroid','What is the role of TSH in monitoring thyroid replacement therapy?','TSH is the most sensitive marker for adequacy of thyroid hormone replacement; target TSH 0.5-2.5 mIU/L for most patients; recheck 6-8 weeks after dose change','CTS guidelines recommend TSH as primary monitoring test for levothyroxine therapy. Avoid over-replacement (low TSH) which causes atrial fibrillation and bone loss. Increased levothyroxine requirements in pregnancy (increase dose by 25-30% immediately upon pregnancy confirmation).',2,'recall',['TSH monitoring','levothyroxine','thyroid replacement','pregnancy','endocrinology']);
add('endo-thyroid','What are the most common types of thyroid cancer and their prognosis?','Papillary (80%, excellent prognosis, 10-year survival >95%); Follicular (10%, good prognosis); Medullary (5%, MEN2-associated, intermediate prognosis, calcitonin marker); Anaplastic (<1%, extremely aggressive, median survival <6 months)','Papillary thyroid carcinoma spreads via lymphatics. BRAF mutation common. Treatment: thyroidectomy ± radioiodine. Medullary thyroid carcinoma: screen for RET mutation and MEN2. Anaplastic carcinoma: no effective treatment, palliative care.',3,'recall',['thyroid cancer','papillary','follicular','medullary','anaplastic','endocrinology']);
add('endo-thyroid','How does amiodarone affect thyroid function?','Amiodarone contains 37% iodine and causes thyrotoxicosis (type 1: excess iodine in pre-existing thyroid disease; type 2: destructive thyroiditis) or hypothyroidism (most common — block of T4→T3 conversion)','Amiodarone-induced thyroid disease occurs in 15-20% of patients. TSH should be checked every 6 months. Type 1 thyrotoxicosis: antithyroid drugs; type 2: corticosteroids; mixed: combination treatment. Hypothyroidism: levothyroxine; may continue amiodarone.',3,'apply',['amiodarone','thyroid dysfunction','hypothyroidism','thyrotoxicosis','endocrinology']);
add('endo-thyroid','What is de Quervain (subacute granulomatous) thyroiditis?','Self-limited thyroiditis following viral illness; painful thyroid, initial hyperthyroidism then hypothyroidism then recovery; ESR elevated, thyroglobulin antibodies negative, radioiodine uptake low','De Quervain thyroiditis phases: hyperthyroid (2-8 weeks) → hypothyroid → recovery (~months). NSAIDs for pain (aspirin of choice). Prednisone for severe cases. Beta-blockers for symptomatic hyperthyroidism. Low RAI uptake distinguishes from Graves.',3,'recall',['de Quervain thyroiditis','subacute thyroiditis','viral thyroiditis','hyperthyroidism','endocrinology']);
add('endo-thyroid','What is postpartum thyroiditis?','Autoimmune thyroiditis within 1 year postpartum: hyperthyroid phase (1-4 months) followed by hypothyroid phase (4-8 months) then recovery; elevated TPO antibodies','Postpartum thyroiditis occurs in 5-9% of women. Distinguished from Graves: no eye disease, RAI uptake low. Hypothyroid phase may require levothyroxine if symptomatic. 20-30% develop permanent hypothyroidism. Recurs in subsequent pregnancies.',3,'recall',['postpartum thyroiditis','autoimmune thyroiditis','TPO antibodies','postpartum','endocrinology']);
add('endo-thyroid','What is the diagnostic approach to hyperthyroidism?','Step 1: TSH (suppressed); Step 2: free T4 and free T3 (elevated); Step 3: etiology — TSH receptor antibodies (TRAb/TSIG) for Graves, thyroid scan and RAI uptake, ultrasound for nodules','Elevated RAI uptake: Graves disease, toxic multinodular goiter, toxic adenoma; Low RAI uptake: thyroiditis (subacute, postpartum, amiodarone type 2), exogenous thyroid hormone, iodine excess. TRAb positive in 90-95% of Graves.',3,'apply',['hyperthyroidism workup','TSH','RAI uptake','TRAb','Graves diagnosis','endocrinology']);

// ENDOCRINOLOGY - endo-adrenal (7)
add('endo-adrenal','A 45-year-old has hypertension, central obesity, moon face, buffalo hump, wide purple striae, and hyperglycemia. What is the diagnosis and screening test?','Cushing syndrome; screen with: 24h urine free cortisol, late-night salivary cortisol (x2), or 1mg overnight dexamethasone suppression test (failure to suppress cortisol to <50 nmol/L)','Endogenous Cushing syndrome most commonly from pituitary ACTH-secreting adenoma (Cushing disease, 65%). Distinguish ACTH-dependent (pituitary or ectopic ACTH) from independent (adrenal adenoma) with plasma ACTH. CRH stimulation and high-dose dexamethasone test to differentiate.',4,'analyze',['Cushing syndrome','cortisol','dexamethasone suppression test','ACTH','endocrinology']);
add('endo-adrenal','What is the approach to primary adrenal insufficiency (Addison disease)?','Primary AI: low cortisol + elevated ACTH + hyponatremia + hyperkalemia + hyperpigmentation; diagnose with cosyntropin stimulation test (peak cortisol <500 nmol/L); treat with hydrocortisone + fludrocortisone','Addison disease is most commonly autoimmune in developed countries. Adrenal crisis precipitated by illness/surgery/stress requires stress dosing. Patients must carry medical alert bracelet. Emergency management: IV hydrocortisone 100mg stat, IV fluids.',4,'apply',['Addison disease','primary adrenal insufficiency','cortisol','hydrocortisone','fludrocortisone','endocrinology']);
add('endo-adrenal','A patient on prednisone 20mg/day for 6 months is having elective surgery. How should perioperative steroids be managed?','Stress-dose corticosteroids: hydrocortisone 50-100mg IV q8h on day of surgery and taper to usual dose over 1-3 days depending on surgical stress (major surgery: 3-5 days)','HPA axis suppression occurs after ≥4 weeks of ≥20mg/day prednisone equivalent. Adrenal crisis with perioperative hypotension is potentially fatal. Any dose of exogenous steroid for >3 weeks requires stress dosing for major procedures. Minor procedures require modest increases.',4,'apply',['perioperative steroids','adrenal suppression','stress dose steroids','HPA axis','endocrinology']);
add('endo-adrenal','What is a pheochromocytoma and what is the pre-operative management?','Catecholamine-secreting adrenal tumor causing hypertensive crises; diagnose with plasma free metanephrines; pre-operative management: alpha-blockade (phenoxybenzamine) ≥2 weeks, then beta-blockade, high-sodium diet','Phenoxybenzamine (non-selective irreversible alpha-blocker) is standard pre-op preparation; alpha-1 selective blockers (doxazosin) also used. Never start beta-blocker before alpha-blocker — may cause hypertensive crisis (unopposed alpha stimulation). IV saline to expand volume pre-operatively.',4,'apply',['pheochromocytoma','pre-operative management','phenoxybenzamine','alpha-blockade','endocrinology']);
add('endo-adrenal','How is secondary adrenal insufficiency differentiated from primary?','Secondary (pituitary): low ACTH, low cortisol, NO hyperkalemia or hyperpigmentation (aldosterone axis intact); Primary (adrenal): high ACTH, low cortisol, hyperkalemia, hyperpigmentation','Secondary AI: pituitary causes (ACTH deficiency), usually from long-term exogenous steroids causing HPA suppression, or pituitary tumor/surgery. No mineralocorticoid deficiency (aldosterone regulated by RAS). Treatment: hydrocortisone alone (no fludrocortisone needed).',3,'apply',['secondary adrenal insufficiency','ACTH','cortisol','pituitary','endocrinology']);
add('endo-adrenal','What is congenital adrenal hyperplasia (CAH) and what is the most common enzyme deficiency?','CAH: autosomal recessive disorder of adrenal steroidogenesis; most common: 21-hydroxylase deficiency (90%): cortisol and aldosterone deficiency, excess androgens — virilization and salt-wasting in classic form','21-hydroxylase deficiency: low cortisol → ACTH excess → adrenal hyperplasia → androgen excess. Classic salt-wasting: ambiguous genitalia in females, adrenal crisis in neonates. Treatment: glucocorticoid replacement suppresses ACTH and androgen excess. Newborn screening in Canada.',4,'recall',['CAH','congenital adrenal hyperplasia','21-hydroxylase','cortisol','endocrinology']);
add('endo-adrenal','What are the indications for adrenalectomy for an adrenal incidentaloma?','Adrenalectomy for: functioning tumors (cortisol-secreting, pheochromocytoma, aldosteronoma), malignant features (>4cm, heterogeneous, irregular, >10 HU on unenhanced CT), rapid growth (>1cm/year)','Adrenal incidentalomas found in ~5% of abdominal CT scans. All incidentalomas require biochemical screening: 1mg DST, plasma metanephrines, aldosterone/renin ratio (if hypertensive). Non-functioning adenomas <4cm: repeat CT in 6-12 months, then annually for 3 years.',3,'apply',['adrenal incidentaloma','adrenalectomy','pheochromocytoma','functional adrenal tumor','endocrinology']);

// ENDOCRINOLOGY - endo-osteo (10)
add('endo-osteo','When should bone mineral density (BMD) testing with DXA be done per Osteoporosis Canada?','Women ≥65 or postmenopausal women <65 with risk factors; men ≥70 or men <70 with risk factors; all patients on long-term steroids (≥3 months at prednisone ≥7.5mg/day)','Osteoporosis Canada guidelines recommend DXA for high-risk individuals. T-score: -1.0 to -2.5 = osteopenia; ≤-2.5 = osteoporosis. FRAX tool estimates 10-year fracture probability to guide treatment decisions.',2,'recall',['DXA','bone mineral density','osteoporosis screening','Osteoporosis Canada','endocrinology']);
add('endo-osteo','What is the pharmacological treatment for osteoporosis in postmenopausal women?','First-line: bisphosphonates (alendronate weekly or zoledronic acid annual infusion); alternatives: denosumab, raloxifene; anabolic: teriparatide or romosozumab for severe osteoporosis','Osteoporosis Canada guidelines recommend treatment for T-score ≤-2.5 or fragility fracture. Bisphosphonates reduce vertebral fractures by 40-70%, hip fractures by 40-50%. Denosumab reduces vertebral fractures by 68%. Calcium 1000-1200 mg/day + vitamin D 800-2000 IU/day for all.',3,'apply',['osteoporosis treatment','bisphosphonates','alendronate','denosumab','endocrinology']);
add('endo-osteo','A 68-year-old woman on alendronate for 7 years has hip pain. Imaging shows cortical thickening of the femoral shaft with a transverse fracture line. Diagnosis?','Atypical femoral fracture (AFF) — bisphosphonate complication; hold bisphosphonate, orthopaedic evaluation, consider anabolic therapy (teriparatide) which may enhance healing','AFFs are rare complications of long-term bisphosphonate use (>3-5 years). Prodromal thigh/groin pain may precede fracture. Radiograph shows transverse fracture with cortical thickening. Both femurs should be evaluated. Drug holiday from bisphosphonate after 5 years if risk-benefit appropriate.',4,'analyze',['atypical femoral fracture','bisphosphonate complication','alendronate','teriparatide','endocrinology']);
add('endo-osteo','What is osteonecrosis of the jaw (ONJ) and when does it occur with osteoporosis treatment?','ONJ: exposed bone in maxillofacial region >8 weeks without healing in patients on antiresorptive therapy; risk highest with IV bisphosphonates/denosumab at cancer doses; rare at osteoporosis doses','Dental assessment before starting antiresorptive therapy is recommended. ONJ risk with oral bisphosphonates for osteoporosis: ~0.001-0.01%. Cancer patients on IV zoledronic acid monthly: much higher risk. Management: conservative oral hygiene, antimicrobials, avoid elective dental surgery.',3,'recall',['osteonecrosis of jaw','ONJ','bisphosphonate complication','denosumab','endocrinology']);
add('endo-osteo','What is hyperparathyroidism and how does it cause bone disease?','Primary HPT: parathyroid adenoma (80%) secretes excess PTH → bone resorption (cortical bone especially) → hypercalcemia, hypophosphatemia, hypercalciuria — treat with parathyroidectomy','Osteitis fibrosa cystica is the bone disease of severe primary HPT (now rare). Presentation: usually asymptomatic hypercalcemia on routine labs. Symptoms: bones (fractures), moans, stones, psychic overtones. DXA for fracture risk assessment. Parathyroidectomy curative.',3,'recall',['primary hyperparathyroidism','PTH','bone disease','parathyroidectomy','endocrinology']);
add('endo-osteo','What is the FRAX tool and how is it used in osteoporosis management?','FRAX: WHO fracture risk assessment tool estimating 10-year probability of major osteoporotic fracture and hip fracture; incorporates age, sex, BMI, BMD, risk factors — guides treatment decisions','Osteoporosis Canada guidelines recommend FRAX to determine treatment thresholds: treat if 10-year major osteoporotic fracture risk ≥20% or hip fracture risk ≥3%. FRAX can be calculated with or without BMD.',2,'recall',['FRAX','fracture risk','osteoporosis','treatment threshold','endocrinology']);
add('endo-osteo','A 70-year-old man on prednisone 15mg/day for polymyalgia rheumatica. What bone protection measures should be initiated?','Calcium (1200 mg/day) + vitamin D (800-2000 IU/day) + bisphosphonate (alendronate or zoledronic acid) started at initiation of steroid therapy for ≥3 months','Glucocorticoid-induced osteoporosis (GIOP) is the most common secondary cause of osteoporosis. Steroids reduce osteoblast function and increase osteoclast activity. Osteoporosis Canada recommends preventive treatment for patients starting ≥7.5mg prednisone/day for ≥3 months.',3,'apply',['glucocorticoid-induced osteoporosis','GIOP','calcium','vitamin D','bisphosphonate','endocrinology']);
add('endo-osteo','What is Paget disease of bone and what treatment is recommended?','Paget: excessive and disorganized bone remodeling causing enlarged, deformed bones (skull, spine, pelvis, femur); markedly elevated ALP; treat symptomatic disease with bisphosphonates (zoledronic acid)','Paget disease presents with bone pain, deformity, increased hat size, hearing loss, high-output heart failure (rare). Diagnosis: markedly elevated ALP, bone scan showing increased uptake in affected areas. Zoledronic acid provides prolonged remission.',3,'recall',['Paget disease','ALP','bisphosphonate','bone remodeling','endocrinology']);
add('endo-osteo','What is vitamin D deficiency and how is it treated?','Vitamin D deficiency (25-OH vitamin D <50 nmol/L): treat with vitamin D3 (cholecalciferol) 1000-2000 IU/day or weekly high-dose loading; recheck in 3 months','Vitamin D deficiency is highly prevalent in Canada due to limited sun exposure. Risk groups: elderly, institutionalized, dark skin, malabsorption, low dietary intake. Osteoporosis Canada recommends vitamin D 800-2000 IU/day for adults at risk for osteoporosis.',2,'recall',['vitamin D deficiency','cholecalciferol','supplementation','osteoporosis prevention','endocrinology']);
add('endo-osteo','A 55-year-old woman has a fragility fracture of her wrist after a minor fall. DXA T-score: -2.7. What is the diagnosis and management?','Osteoporosis with fragility fracture; initiate pharmacotherapy (bisphosphonate first-line) regardless of T-score when fragility fracture has occurred, plus calcium + vitamin D','Fragility fractures are defined as fractures from a fall from standing height or less. Any fragility fracture at major sites (hip, spine, wrist) qualifies as osteoporosis regardless of BMD. Hip fractures have 20-30% mortality within 1 year.',3,'apply',['fragility fracture','osteoporosis','bisphosphonate','treatment threshold','endocrinology']);

// INFECTIOUS DISEASE - id-hiv (15)
add('id-hiv','A 32-year-old has fever, pharyngitis, lymphadenopathy, and a maculopapular rash 3 weeks after unprotected sex. HIV viral load is 850,000 copies/mL, CD4 count 540. What is the diagnosis?','Acute HIV seroconversion (primary HIV infection); viral load peaks, CD4 transiently drops; standard HIV ELISA/Western blot may be negative — use 4th generation test (HIV Ag/Ab combo assay)','Acute HIV presents 2-4 weeks after transmission as a mononucleosis-like illness. 4th generation HIV Ag/Ab tests detect p24 antigen before antibody seroconversion. AMMI Canada/PHAC guidelines recommend immediate ART regardless of CD4 count.',4,'analyze',['acute HIV','seroconversion','HIV testing','4th generation','infectious disease']);
add('id-hiv','What is the first-line ART regimen for treatment-naive HIV patients per DHHS/CIHR guidelines?','Preferred: bictegravir/tenofovir alafenamide/emtricitabine (BIC/TAF/FTC, Biktarvy) — single tablet regimen; alternative: dolutegravir + TAF/FTC (Dovato) or other INSTI-based regimens','INSTI (integrase strand transfer inhibitor)-based regimens are preferred for treatment-naive patients due to high potency, tolerability, and high barrier to resistance. Goal: undetectable viral load (<50 copies/mL) within 3-6 months. Resistance testing before starting ART.',3,'recall',['HIV ART','antiretroviral therapy','bictegravir','Biktarvy','INSTI','infectious disease']);
add('id-hiv','A 40-year-old with HIV and CD4 count of 85 cells/μL develops progressive dyspnea, bilateral interstitial infiltrates, and SpO2 88%. LDH is elevated. Diagnosis and treatment?','Pneumocystis jirovecii pneumonia (PCP); treat with TMP-SMX (15-20 mg/kg/day of TMP) + prednisone if PaO2 <70 mmHg; adjunctive steroids reduce mortality','PCP is the most common AIDS-defining opportunistic infection when CD4 <200. Serum beta-D-glucan elevated. BAL with immunofluorescence or PCR confirms diagnosis. Primary prophylaxis with TMP-SMX when CD4 <200.',4,'apply',['PCP','Pneumocystis','HIV','TMP-SMX','CD4 count','infectious disease']);
add('id-hiv','What are the opportunistic infection prophylaxis thresholds in HIV?','CD4 <200: PCP prophylaxis (TMP-SMX DS daily); CD4 <100: toxoplasmosis prophylaxis (TMP-SMX DS also covers); CD4 <50: MAC prophylaxis (azithromycin weekly)','AMMI Canada/PHAC guidelines recommend OI prophylaxis based on CD4 count. Prophylaxis can be discontinued when CD4 consistently >200 (PCP), >100 (toxo), >100 (MAC) on ART. CMV retinitis occurs at CD4 <50 — ganciclovir.',3,'recall',['HIV prophylaxis','CD4 count','PCP prophylaxis','TMP-SMX','MAC','infectious disease']);
add('id-hiv','What is HIV pre-exposure prophylaxis (PrEP) and who should be offered it?','PrEP: daily oral tenofovir/emtricitabine (TDF/FTC or TAF/FTC) for HIV-negative individuals at high risk; reduces transmission by >99% if adherent','PHAC and CATIE recommend offering PrEP to HIV-negative individuals with ongoing high-risk sexual behavior (MSM with multiple partners, serodiscordant couples, people who inject drugs). On-demand PrEP (2-1-1 protocol) is an alternative for MSM. Baseline and 3-monthly HIV testing required.',3,'apply',['PrEP','HIV prevention','tenofovir','emtricitabine','infectious disease']);
add('id-hiv','A patient on ART has a rising HIV viral load after being undetectable. What is the approach?','Confirm with repeat VL; assess adherence (most common cause); resistance testing; review drug interactions; switch to fully active regimen based on resistance profile','Treatment failure is defined as confirmed viral load >200 copies/mL on ART. AMMI guidelines recommend resistance testing before switching. Switch to regimen with ≥2 fully active drugs. Adherence counseling is crucial — 95% adherence required to suppress HIV.',4,'analyze',['HIV treatment failure','viral load','resistance testing','ART switch','infectious disease']);
add('id-hiv','What AIDS-defining conditions occur at CD4 <50 cells/μL?','Disseminated MAC (Mycobacterium avium complex), CMV retinitis/disease, CNS lymphoma, disseminated histoplasmosis, disseminated coccidioidomycosis, Cryptosporidium','AMMI guidelines define AIDS as CD4 <200 or the presence of AIDS-defining conditions. CMV retinitis presents with visual floaters/blind spots — ganciclovir treatment. MAC presents with fever, night sweats, weight loss, diarrhea — azithromycin + ethambutol.',3,'recall',['AIDS-defining conditions','CD4 count <50','MAC','CMV retinitis','infectious disease']);
add('id-hiv','How is HIV transmitted and what are the relative transmission risks?','Receptive anal intercourse (1.4%/act highest risk), insertive anal (0.11%), receptive vaginal (0.08%), needle sharing (0.63%); negligible: oral sex, intact skin, casual contact; NOT transmitted by saliva, tears, hugging','Understanding transmission guides prevention counseling. Viral load strongly influences transmission risk. Undetectable = untransmittable (U=U) when viral load suppressed on ART. Condoms reduce risk by ~80-85% for sexual transmission.',2,'recall',['HIV transmission','risk per act','U=U','prevention','infectious disease']);
add('id-hiv','A healthcare worker has a needlestick injury from an HIV-positive source patient (viral load 40,000). What should be done?','Immediate post-exposure prophylaxis (PEP): within 2 hours (no later than 72h) with 28 days of BIC/TAF/FTC or DTG + TDF/FTC; report incident; baseline HIV, HBV, HCV testing','PEP reduces HIV transmission by ~80%. Baseline and 4-6 week repeat HIV testing. Source patient hepatitis B status: give HBIG + vaccine if source HBsAg+ and worker not immune. AMMI/PHAC guidelines for occupational exposure.',4,'apply',['PEP','post-exposure prophylaxis','needlestick','HIV prevention','occupational exposure','infectious disease']);
add('id-hiv','What are the immune reconstitution inflammatory syndrome (IRIS) and when does it occur?','IRIS: paradoxical worsening or unmasking of opportunistic infections within weeks-months of starting ART as immune system recovers; risk highest when starting ART with low CD4 and concurrent OI','IRIS occurs in ~17% of patients starting ART with CD4 <100. Most common IRIS: TB-IRIS, MAC-IRIS, cryptococcal IRIS. Management: continue ART in most cases; NSAIDs or corticosteroids for severe symptoms. Delay ART if active OI being treated (except TB, CMV — start ART).',4,'analyze',['IRIS','immune reconstitution','opportunistic infection','ART','infectious disease']);
add('id-hiv','What is the recommended HIV testing approach in Canada for screening?','4th generation HIV Ag/Ab combination test for screening; reactive result confirmed with HIV differentiation assay; routine testing offered to all adults 15-65, all pregnant women, and targeted testing for high-risk groups','PHAC/CTFPHC recommend opt-out HIV testing in high-prevalence settings. HIV testing in pregnancy: routine universal testing at first prenatal visit. Reporting requirements: positive HIV test is reportable in all Canadian provinces/territories.',2,'recall',['HIV testing','4th generation assay','screening','PHAC','infectious disease']);
add('id-hiv','A 45-year-old with HIV has a CD4 count of 50 and starts ART. What timing is recommended relative to treating concurrent cryptococcal meningitis?','Delay ART for 4-6 weeks after starting antifungal treatment for cryptococcal meningitis — early ART associated with increased mortality from IRIS','The COAT trial demonstrated that immediate ART with cryptococcal meningitis increases mortality versus deferred ART. Treat with amphotericin B + flucytosine induction for 2 weeks, then fluconazole consolidation before starting ART.',5,'analyze',['cryptococcal meningitis','ART timing','IRIS','amphotericin B','infectious disease']);
add('id-hiv','What monitoring is recommended for patients on HIV ART?','At initiation: baseline CBC, BMP, LFTs, HBV/HCV, urinalysis, lipid panel, resistance testing, HLA-B*5701 (abacavir hypersensitivity); Follow-up: viral load q3 months until undetectable, then q6 months; CD4 when VL detectable; annual lipid, renal function','AMMI HIV guidelines outline monitoring schedule. HLA-B*5701 testing mandatory before prescribing abacavir to prevent potentially fatal hypersensitivity reaction. CD4 monitoring less essential once virally suppressed.',2,'recall',['HIV monitoring','ART','viral load','CD4','HLA-B5701','infectious disease']);
add('id-hiv','What hepatitis co-infections are common in HIV and how do they affect management?','HIV/HBV co-infection (use TAF/FTC or TDF/FTC which treats both); HIV/HCV co-infection (treat HCV first with DAAs, then ART — check for drug interactions)','HBV co-infection requires HIV regimen containing tenofovir (treats both viruses). Never treat HBV with lamivudine or emtricitabine alone in HIV-positive patients (promotes HBV resistance). HCV DAAs are highly effective in HIV/HCV co-infection (similar SVR rates to HIV-negative).',3,'apply',['HIV HBV co-infection','HIV HCV co-infection','tenofovir','DAA therapy','infectious disease']);
add('id-hiv','What antiretroviral drug class is associated with lipodystrophy, dyslipidemia, and insulin resistance?','Older protease inhibitors (lopinavir/ritonavir, indinavir) and older NRTIs (stavudine d4T, zidovudine AZT) cause metabolic complications — modern ART (INSTI, TAF-based) has much improved metabolic profile','HIV-associated lipodystrophy: peripheral lipoatrophy (fat wasting from face, limbs) and central lipohypertrophy (visceral fat, buffalo hump). Modern ART agents (TAF > TDF for renal/bone; INSTIs metabolically neutral). Cardiovascular risk monitoring important in HIV patients.',3,'recall',['lipodystrophy','HIV metabolic complications','protease inhibitors','NRTI','infectious disease']);

// INFECTIOUS DISEASE - id-sepsis (15)
add('id-sepsis','A 68-year-old has altered consciousness, fever 39.5°C, BP 88/52, HR 124, RR 28, lactate 3.2 mmol/L. What is the diagnosis and the Surviving Sepsis 1-hour bundle?','Septic shock (sepsis + vasopressor requirement OR lactate ≥2 mmol/L); 1-hour bundle: blood cultures, IV broad-spectrum antibiotics, 30 mL/kg IV crystalloid, vasopressors for MAP <65 if no response','Sepsis-3 definition: life-threatening organ dysfunction from infection. SOFA score ≥2 acute change. Quick-SOFA (altered mental status, RR ≥22, SBP ≤100) identifies high-risk patients outside ICU. Surviving Sepsis Campaign 2021: 1-hour bundle.',5,'analyze',['septic shock','Surviving Sepsis','1-hour bundle','SOFA score','infectious disease']);
add('id-sepsis','What are the diagnostic criteria for sepsis vs. septic shock per Sepsis-3?','Sepsis: suspected infection + acute SOFA score ≥2; Septic shock: sepsis + vasopressor requirement to maintain MAP ≥65 AND serum lactate >2 mmol/L despite adequate fluid resuscitation','Sepsis-3 eliminated SIRS criteria for sepsis definition. SOFA (Sequential Organ Failure Assessment) assesses respiratory, coagulation, liver, cardiovascular, CNS, renal. Previous definitions (severe sepsis) are no longer used.',2,'recall',['Sepsis-3','SOFA','septic shock','sepsis definition','infectious disease']);
add('id-sepsis','What is the first-line vasopressor in septic shock and what is the MAP target?','Norepinephrine is first-line vasopressor; target MAP ≥65 mmHg — higher targets (80-85) may benefit patients with chronic hypertension','Surviving Sepsis guidelines recommend norepinephrine as first-line due to lower arrhythmia risk vs. dopamine (SOAP II trial). Vasopressin (0.03 units/min) added as second agent to reduce norepinephrine dose or for refractory shock. Epinephrine as third-line. Dopamine only if low tachyarrhythmia risk.',3,'recall',['norepinephrine','vasopressor','septic shock','MAP target','infectious disease']);
add('id-sepsis','How should blood cultures be obtained in sepsis and when should antibiotics be given?','2-3 sets of blood cultures (aerobic + anaerobic) from 2 different sites before antibiotics; antibiotics within 1 hour for septic shock, 3 hours for sepsis without shock','Surviving Sepsis 2021: delay antibiotics to get cultures should not exceed 45 minutes. Each hour delay in antibiotics in septic shock increases mortality ~7%. Give broad-spectrum empiric coverage, then narrow based on cultures and sensitivities (antibiotic stewardship).',3,'apply',['blood cultures','antibiotics timing','sepsis','antibiotic stewardship','infectious disease']);
add('id-sepsis','What IV fluid is recommended in early sepsis resuscitation?','30 mL/kg balanced crystalloid (Lactated Ringer preferred, or NS); SMART trial showed LR reduces mortality and AKI compared to normal saline','Surviving Sepsis recommends 30 mL/kg IV crystalloid in first 3 hours. Albumin may be added if large volumes of crystalloid required. Reassess after each fluid bolus using dynamic measures (passive leg raise, pulse pressure variation). Avoid fluid overload — associated with worse outcomes.',3,'apply',['IV fluids','fluid resuscitation','Lactated Ringer','sepsis','balanced crystalloid','infectious disease']);
add('id-sepsis','When are corticosteroids indicated in septic shock?','IV hydrocortisone 200 mg/day (50mg q6h or 200mg continuous infusion) in septic shock refractory to adequate fluids and vasopressors (norepinephrine >0.25 μg/kg/min)','APROCCHSS trial showed hydrocortisone + fludrocortisone reduces mortality in severe septic shock. Surviving Sepsis recommends IV hydrocortisone for vasopressor-refractory septic shock. ACTH stimulation test is NOT required before giving steroids.',4,'apply',['corticosteroids','septic shock','hydrocortisone','vasopressor-refractory','infectious disease']);
add('id-sepsis','What empiric antibiotic coverage is recommended for community-acquired sepsis of unknown source?','Broad-spectrum coverage: piperacillin-tazobactam or a carbapenem (meropenem/imipenem) + coverage for community MRSA (vancomycin) if risk factors (IV drug use, prior MRSA, healthcare contact)','Antibiotic choice depends on suspected source, local resistance patterns, and patient risk factors. De-escalation after 24-48h based on culture results. Duration should be as short as effective (7-10 days for most community sepsis). Source control (drain abscesses, remove infected lines) is essential.',4,'apply',['empiric antibiotics','sepsis','piperacillin-tazobactam','MRSA','antibiotic stewardship','infectious disease']);
add('id-sepsis','What is source control in sepsis and what are examples?','Rapid intervention to control the infectious source: drain abscess (percutaneous or surgical), remove infected IV line/catheter, debride infected tissue, restore bowel continuity for perforated viscus','Surviving Sepsis guidelines recommend source control within 6-12 hours. Infected central venous catheters should be removed as soon as possible. ECMO or surgical intervention for severe necrotizing fasciitis or gas gangrene. Antibiotic therapy alone is insufficient when a nidus of infection remains.',3,'recall',['source control','sepsis management','abscess drainage','infected catheter','infectious disease']);
add('id-sepsis','What is DIC (disseminated intravascular coagulation) in the context of sepsis?','DIC: systemic activation of coagulation cascade leading to microthrombi and consumption coagulopathy; labs: low platelets, prolonged PT/INR, low fibrinogen, elevated D-dimer; treat underlying sepsis','DIC complicates severe sepsis, trauma, and obstetric emergencies. Paradoxically causes both thrombosis (organ failure) and bleeding (factor consumption). Treat underlying cause. Replace blood products for active bleeding: platelets (PLT <50), FFP, cryoprecipitate (low fibrinogen <1.5 g/L).',4,'analyze',['DIC','disseminated intravascular coagulation','sepsis complication','coagulopathy','infectious disease']);
add('id-sepsis','What is the Surviving Sepsis Bundle for mechanical ventilation in septic shock?','Lung-protective ventilation: tidal volume 6 mL/kg ideal body weight, plateau pressure <30 cmH2O, PEEP titration, permissive hypercapnia; prone positioning if PaO2/FiO2 <150','ARDSNET and PROSEVA trials support low-tidal volume ventilation and prone positioning in ARDS (common in severe sepsis). Avoid high plateau pressures — cause ventilator-induced lung injury (VILI). Target SpO2 94-98%.',4,'apply',['mechanical ventilation','lung protective','ARDS','prone positioning','sepsis management','infectious disease']);
add('id-sepsis','What is procalcitonin (PCT) and how is it used in sepsis management?','PCT rises with bacterial infections (but not viral); elevated PCT supports bacterial sepsis diagnosis; serial PCT used to guide antibiotic discontinuation (PCT-guided de-escalation reduces antibiotic exposure)','PRORATA trial showed PCT-guided antibiotic discontinuation reduces antibiotic days without worsening outcomes. PCT is most useful for guiding antibiotic duration (stop when PCT falls to 80% of peak or <0.5 ng/mL). Less useful for diagnosis as it can be elevated in non-infectious conditions.',3,'apply',['procalcitonin','PCT','antibiotic stewardship','sepsis diagnosis','de-escalation','infectious disease']);
add('id-sepsis','What glycemic target is recommended in ICU patients with sepsis?','Maintain blood glucose 7.8-10 mmol/L with insulin infusion — avoid both hyperglycemia and hypoglycemia','NICE-SUGAR trial showed moderate glucose control (≤10 mmol/L) reduces mortality compared to tight control (≤6.1 mmol/L), which increased hypoglycemia. Intensive insulin therapy associated with increased severe hypoglycemia events. Surviving Sepsis recommends insulin when glucose >10 mmol/L x2.',3,'recall',['glucose control','ICU','insulin','glycemic target','sepsis','infectious disease']);
add('id-sepsis','What is lactate-guided resuscitation in sepsis?','Measure serum lactate at presentation; if ≥4 mmol/L indicates severe hypoperfusion — resuscitate to achieve lactate clearance ≥10-20% per 2 hours; repeat lactate 2h after initial resuscitation','LACTATE trial showed early lactate measurement and lactate-guided resuscitation reduces mortality. Lactate ≥2 mmol/L = criterion for septic shock. Persistently elevated lactate despite resuscitation suggests occult hypoperfusion.',3,'apply',['lactate','sepsis resuscitation','tissue hypoperfusion','lactate clearance','infectious disease']);
add('id-sepsis','What is the FAST-HUG mnemonic for daily ICU care in sepsis patients?','Feeding (enteral nutrition), Analgesia, Sedation (minimizing), Thromboprophylaxis, Head-of-bed elevation (30-45°), Ulcer prophylaxis (stress ulcer), Glucose control','Surviving Sepsis guidelines recommend light sedation (target RASS 0 to -1), early enteral nutrition, DVT prophylaxis (LMWH preferred), HOB elevation to prevent VAP, stress ulcer prophylaxis with PPI (if high risk), glycemic control.',2,'recall',['FAST-HUG','ICU care bundle','sepsis management','sedation','DVT prophylaxis','infectious disease']);
add('id-sepsis','What is the qSOFA score and how is it used?','qSOFA: RR ≥22/min (1), altered mentation (1), SBP ≤100 mmHg (1); score ≥2 identifies patients with suspected infection at risk of poor outcomes — use outside ICU to identify high-risk patients','qSOFA is a bedside screening tool that does not require labs. Positive qSOFA (≥2) should prompt full SOFA assessment and consideration of ICU-level care. Not as sensitive as SIRS for identifying all sepsis, but more specific for poor outcomes.',2,'recall',['qSOFA','sepsis screening','SOFA','organ dysfunction','infectious disease']);

// INFECTIOUS DISEASE - id-sti (10)
add('id-sti','A 22-year-old woman has mucopurulent cervical discharge and cervical motion tenderness. Cervical NAAT is positive for Chlamydia trachomatis. Diagnosis and treatment?','Chlamydial cervicitis (or pelvic inflammatory disease if upper tract involvement); treat with doxycycline 100mg BID x7 days (or azithromycin 1g single dose for uncomplicated)','PHAC/AMMI STI guidelines recommend doxycycline as preferred treatment for chlamydial infections; azithromycin single-dose acceptable for uncomplicated urethral/cervical infection but inferior for rectal chlamydia. Test-of-cure not routinely required. Treat partners within 60 days.',3,'apply',['chlamydia','STI','doxycycline','cervicitis','infectious disease']);
add('id-sti','What is the treatment for gonorrhea per current Canadian guidelines?','Ceftriaxone 500 mg IM single dose (1g if weight >150kg); test-of-cure recommended at 1 week; treat all partners and retest for chlamydia','PHAC STI guidelines updated due to rising fluoroquinolone and azithromycin resistance in Neisseria gonorrhoeae. Ceftriaxone remains effective. Dual therapy (with azithromycin) no longer recommended routinely. Disseminated gonococcal infection (septic arthritis, skin lesions): IV ceftriaxone.',3,'apply',['gonorrhea','ceftriaxone','NAAT','STI treatment','infectious disease']);
add('id-sti','A pregnant woman has a positive RPR (1:64) and positive FTA-ABS. She has no prior treatment. What is the treatment?','Primary/secondary/early latent syphilis in pregnancy: benzathine penicillin G 2.4 million units IM single dose — penicillin allergy: desensitize and give penicillin (no safe alternatives in pregnancy)','PHAC STI guidelines: all pregnant women should be screened for syphilis at first prenatal visit and at 28-32 weeks (and delivery) in high-prevalence areas. Congenital syphilis is preventable with timely treatment. Penicillin is the only proven treatment to prevent congenital transmission.',4,'apply',['syphilis in pregnancy','benzathine penicillin','congenital syphilis','RPR','SOGC','infectious disease']);
add('id-sti','What are the stages of syphilis and their clinical features?','Primary: painless chancre (2-3 weeks post-exposure); Secondary: diffuse maculopapular rash including palms/soles, condylomata lata, mucous patches (6-8 weeks); Latent: asymptomatic; Tertiary: gummas, cardiovascular (aortitis), neurosyphilis','All stages require treatment. Late latent or unknown duration syphilis: benzathine penicillin G 2.4 million units IM x3 weeks. Neurosyphilis: IV penicillin G for 10-14 days. Diagnosis: RPR/VDRL (non-treponemal) + FTA-ABS/TPPA (treponemal confirmatory).',3,'recall',['syphilis stages','primary syphilis','secondary syphilis','treatment','infectious disease']);
add('id-sti','What is pelvic inflammatory disease (PID) and how is it treated?','PID: infection of upper female genital tract (endometrium, fallopian tubes, ovaries); treat outpatient with ceftriaxone 500mg IM single dose + doxycycline 100mg BID x14 days + metronidazole 500mg BID x14 days','PID is usually polymicrobial (N. gonorrhoeae, C. trachomatis, anaerobes). Laparoscopy is gold standard for diagnosis but not required. Sequelae: chronic pelvic pain, infertility, ectopic pregnancy. Hospitalise if: severe illness, tubo-ovarian abscess, pregnancy, surgical emergency cannot be excluded.',4,'apply',['PID','pelvic inflammatory disease','ceftriaxone','doxycycline','STI treatment','infectious disease']);
add('id-sti','A 27-year-old man has painful penile vesicles that ulcerate. Tzanck smear shows multinucleated giant cells. Diagnosis and treatment?','Genital herpes (HSV-2 most common, HSV-1 also possible); treat with oral acyclovir 400mg TID x7-10 days for primary episode, or valacyclovir 1g BID x5-10 days','PHAC STI guidelines recommend antiviral therapy for all primary genital herpes episodes regardless of symptom duration. Suppressive therapy (valacyclovir 500mg OD daily) reduces recurrences and transmission. PCR is more sensitive than Tzanck smear for diagnosis.',3,'apply',['genital herpes','HSV','acyclovir','valacyclovir','STI treatment','infectious disease']);
add('id-sti','What is HIV post-exposure prophylaxis (PEP) for sexual exposure and what are the criteria?','PEP: TDF/FTC + bictegravir (or DTG/RAL) for 28 days; start within 72 hours of exposure; indicated for high-risk exposures (unprotected anal/vaginal sex with HIV-positive source or unknown status in high-prevalence setting)','PHAC guidelines recommend PEP for receptive anal sex with HIV-positive partner (highest risk). Risk assessment using estimated transmission probability. Document HIV-negative status of recipient before starting. Follow-up HIV testing at 4-6 weeks and 3 months. Discuss PrEP transition.',4,'apply',['PEP','HIV post-exposure','sexual exposure','TDF/FTC','infectious disease']);
add('id-sti','What is the recommended screening frequency for STIs in sexually active MSM?','Syphilis, gonorrhea (pharynx, rectum, urethra), chlamydia every 3 months if high-risk (multiple partners, no consistent condom use, illicit drug use during sex, partner with STI/HIV)','PHAC STI guidelines recommend more frequent screening for MSM at high risk. Regular HIV and hepatitis C testing recommended. HPV vaccine recommended for MSM up to age 45. Hepatitis A and B vaccination.',2,'recall',['MSM screening','STI screening','gonorrhea','chlamydia','syphilis','infectious disease']);
add('id-sti','A 25-year-old woman has a thin homogeneous vaginal discharge with fishy odor (whiff test positive). Clue cells seen on wet mount. Diagnosis and treatment?','Bacterial vaginosis; treat with metronidazole 500mg BID x7 days or metronidazole 0.75% vaginal gel x5 days or clindamycin vaginal cream x7 days','Bacterial vaginosis results from overgrowth of anaerobes (Gardnerella vaginalis) replacing normal Lactobacillus flora. Amsel criteria (3 of 4): thin homogeneous discharge, clue cells, vaginal pH >4.5, positive whiff test. Partners do not require treatment (not an STI).',3,'apply',['bacterial vaginosis','BV','metronidazole','clue cells','infectious disease']);
add('id-sti','What is the treatment for Trichomonas vaginalis infection?','Metronidazole 2g PO single dose (or 500mg BID x7 days) for both patient and sexual partners simultaneously','Trichomoniasis is the most common curable STI. Presentations: yellow-green frothy discharge, vulvar pruritus, "strawberry cervix" (punctate hemorrhages). PHAC guidelines: treat all sexual partners. Test-of-cure recommended if symptoms persist.',2,'apply',['trichomoniasis','Trichomonas','metronidazole','STI treatment','infectious disease']);

// INFECTIOUS DISEASE - id-tb (10)
add('id-tb','A 35-year-old immigrant from a TB-endemic country has a positive IGRA (QuantiFERON-TB Gold). CXR is normal. No symptoms. What is the diagnosis and management?','Latent TB infection (LTBI); treat with isoniazid 9 months (INH 9H) or rifampin 4 months (RIF 4R) or isoniazid + rifapentine (1HP) once weekly x12 weeks (DOTS)','AMMI Canada and CATSS guidelines recommend LTBI treatment for all immunocompetent adults <50 years with positive IGRA/TST. Rifampin 4 months (4R) has equivalent efficacy to INH 9 months with better completion rates. INH requires pyridoxine to prevent peripheral neuropathy.',3,'apply',['LTBI','latent TB','isoniazid','IGRA','tuberculosis','infectious disease']);
add('id-tb','A 40-year-old with productive cough, hemoptysis, weight loss, and night sweats for 3 months. CXR shows upper lobe cavitation. AFB smear is positive. Diagnosis and initial treatment?','Active pulmonary tuberculosis; initiate 4-drug therapy: RIPE (Rifampin + Isoniazid + Pyrazinamide + Ethambutol) for 2 months, then Rifampin + Isoniazid for 4 months (total 6 months)','AMMI Canada TB guidelines recommend standard 6-month DOTS therapy (directly observed therapy short-course). RIPE initiation phase x2 months, followed by 4-month RI continuation phase. Drug sensitivity testing guides modifications. Isolate patient in negative-pressure room during infectious period.',4,'apply',['active tuberculosis','RIPE','directly observed therapy','pulmonary TB','infectious disease']);
add('id-tb','What is the role of drug susceptibility testing (DST) in TB management?','All initial Mycobacterium tuberculosis isolates should have DST performed; guides treatment modifications; MDR-TB (resistant to INH + RIF) requires specialized regimens','MDR-TB (multidrug-resistant) requires 18-20+ month treatment with second-line drugs. XDR-TB additionally resistant to fluoroquinolones and second-line injectables. Bedaquiline, linezolid, and pretomanid are newer agents for MDR-TB. All TB in Canada is reportable.',3,'recall',['MDR-TB','drug susceptibility','DST','tuberculosis treatment','infectious disease']);
add('id-tb','What are the side effects of isoniazid (INH) and how are they monitored?','Peripheral neuropathy (prevented by pyridoxine 25-50mg/day), hepatotoxicity (hold if ALT >3-5x ULN), drug-induced lupus','INH hepatotoxicity risk increases with age, alcohol use, and pre-existing liver disease. Monitor LFTs monthly in patients at risk. INH inhibits CYP2E1 and is a MAO inhibitor — dietary interactions (tyramine). INH inhibits metabolism of phenytoin and warfarin.',3,'apply',['isoniazid side effects','INH hepatotoxicity','pyridoxine','tuberculosis treatment','infectious disease']);
add('id-tb','A patient with HIV and CD4 count 80 cells/μL is diagnosed with active TB. When should ART be initiated?','Start ART within 2-8 weeks of starting TB therapy (regardless of CD4 count) — early ART reduces mortality in HIV/TB co-infection','AMMI Canada guidelines recommend early ART in HIV-TB co-infection (SAPIT trial). Exception: CD4 >50 and extrapulmonary TB other than meningitis — can delay 8 weeks. TB meningitis: delay ART 8 weeks due to higher IRIS risk (worsens mortality). Rifampin induces CYP3A4 — dose-adjust certain ARVs.',5,'analyze',['HIV TB co-infection','ART timing','IRIS','rifampin','infectious disease']);
add('id-tb','How is TB infection diagnosed in Canada — when to use TST vs. IGRA?','IGRA (QuantiFERON-TB Gold, T-SPOT.TB) preferred for: BCG-vaccinated, immunocompromised; TST (tuberculin skin test) preferred for: children <5, prior positive IGRA; either acceptable for most adults','CATSS/AMMI guidelines recommend IGRA over TST in BCG-vaccinated individuals as BCG causes false-positive TST. IGRA is also preferred in immunocompromised patients. Two-step TST used in healthcare worker surveillance programs.',2,'recall',['IGRA','TST','TB testing','BCG','tuberculosis','infectious disease']);
add('id-tb','What are the public health obligations when a new case of active TB is identified?','Mandatory reporting to public health within 24h; contact investigation to identify exposed individuals; LTBI testing and treatment for close contacts; DOT (directly observed therapy) for high-risk patients','AMMI Canada and PHAC guidelines require that all active TB cases be reported to the local health unit. Contact investigations use the concentric-circle approach. Priority contacts: household, close contacts. High-risk contacts (children <5, immunocompromised) receive LTBI prophylaxis.',3,'recall',['TB public health','mandatory reporting','contact investigation','DOT','infectious disease']);
add('id-tb','What radiographic findings are typical of primary vs. post-primary (reactivation) TB?','Primary: lower or mid-lobe consolidation, hilar lymphadenopathy, pleural effusion; Reactivation: upper lobe cavitation, fibrosis, calcified nodules (Ghon complex)','Primary TB occurs with initial infection — lymphadenopathy and lower lobe infiltrate from haematogenous spread. Reactivation TB: upper lobe predilection (high O2 tension) with classic cavitation and apical scarring. Miliary TB: hematogenous dissemination, diffuse 1-2mm nodules.',3,'recall',['TB radiology','primary TB','reactivation TB','cavitation','infectious disease']);
add('id-tb','What is extensively drug-resistant TB (XDR-TB) and what treatment options exist?','XDR-TB: MDR-TB + resistance to fluoroquinolones; newer regimens: BPaL (bedaquiline + pretomanid + linezolid) — ~90% treatment success in clinical trials (ZeNix, TB-PRACTECAL trials)','XDR-TB was previously almost untreatable. BPaL regimen (ZeNix trial) showed 90% success at 26 weeks — revolutionizing MDR/XDR-TB treatment. Bedaquiline + delamanid combinations also used. All cases require specialized MDR-TB centres for management.',4,'analyze',['XDR-TB','MDR-TB','bedaquiline','BPaL','pretomanid','infectious disease']);
add('id-tb','What are the indications for LTBI treatment in immunocompromised patients in Canada?','All HIV-positive patients (regardless of IGRA/TST result if from endemic country), patients starting anti-TNF therapy, organ transplant recipients, patients starting high-dose steroids — treat LTBI before immunosuppression when possible','CATSS guidelines recommend LTBI testing and treatment before biologic therapies (especially anti-TNF). TNF inhibitors increase TB reactivation risk 5-25 fold. Repeat LTBI testing annually in high-risk groups. Rifampin preferred over INH when on biologic therapy (shorter duration).',4,'apply',['LTBI treatment','immunocompromised','anti-TNF','HIV','tuberculosis','infectious disease']);

// INFECTIOUS DISEASE - id-meningitis (10)
add('id-meningitis','A 22-year-old college student has sudden onset of severe headache, high fever, nuchal rigidity, and photophobia. Kernig and Brudzinski signs are positive. What is the diagnosis and immediate management?','Bacterial meningitis; give IV dexamethasone 0.15 mg/kg q6h + IV ceftriaxone 2g q12h immediately — do NOT delay for CT or LP if clinical diagnosis clear','AMMI Canada guidelines recommend immediate empiric antibiotics in suspected bacterial meningitis without awaiting LP if CT or LP would be delayed >30-60 minutes. Add ampicillin if age >50 or immunocompromised (Listeria coverage). Dexamethasone 20 min before first antibiotic dose reduces neurological sequelae.',5,'analyze',['bacterial meningitis','ceftriaxone','dexamethasone','immediate treatment','infectious disease']);
add('id-meningitis','What CSF findings differentiate bacterial from viral meningitis?','Bacterial: WBC >1000 (PMN predominance), protein >1 g/L, glucose <2.2 mmol/L (CSF:serum ratio <0.4), positive Gram stain 60-90%; Viral: WBC 10-500 (lymphocytes), normal/mildly elevated protein, normal glucose','Additional CSF tests for bacterial meningitis: procalcitonin, lactate (>3.5 mmol/L suggests bacterial). PCR panels can rapidly identify pathogens (N. meningitidis, S. pneumoniae, L. monocytogenes, HSV). Opening pressure elevated in bacterial meningitis (>25 cm H2O).',3,'apply',['CSF findings','bacterial meningitis','viral meningitis','LP interpretation','infectious disease']);
add('id-meningitis','What organisms cause bacterial meningitis by age group?','Neonates: Group B Strep, E. coli, Listeria; Adults <50: S. pneumoniae, N. meningitidis; Adults >50: S. pneumoniae, Listeria, Gram-negatives; HIV: Cryptococcus, Listeria; Post-neurosurgery: Staphylococcus, Gram-negatives','Empiric treatment must cover likely pathogens for age group. Ampicillin added for Listeria coverage in elderly, pregnant, immunocompromised. Meningococcal meningitis: droplet precautions, prophylactic rifampin/ciprofloxacin for close contacts.',3,'recall',['meningitis organisms','S. pneumoniae','N. meningitidis','Listeria','infectious disease']);
add('id-meningitis','When is CT head required before lumbar puncture in suspected meningitis?','CT required before LP if: new focal neurological deficit, papilledema, new onset seizures, altered consciousness, or immunocompromised — risk of herniation','AMMI Canada guidelines recommend CT only in patients with risk factors for herniation. Normal CT does not completely exclude elevated ICP or prevent herniation. If CT required, do not delay antibiotics — blood cultures + antibiotics before CT, then LP.',3,'apply',['CT before LP','meningitis','herniation risk','lumbar puncture','infectious disease']);
add('id-meningitis','What is meningococcal prophylaxis and who requires it?','Rifampin 600mg PO BID x2 days OR ciprofloxacin 500mg PO single dose — for household contacts, childcare contacts, anyone with direct exposure to oral secretions within 7 days of illness onset','PHAC guidelines: close contacts of meningococcal meningitis require prophylaxis within 24 hours (no benefit after 14 days). Chemoprophylaxis eliminates nasopharyngeal carriage. Ceftriaxone is alternative in pregnancy (rifampin and cipro relatively contraindicated).',3,'apply',['meningococcal prophylaxis','rifampin','ciprofloxacin','contacts','infectious disease']);
add('id-meningitis','A 65-year-old is HIV-positive with CD4 count 40 and has subacute meningitis with headache and confusion. India ink stain of CSF shows encapsulated yeast. Diagnosis and treatment?','Cryptococcal meningitis; treat with amphotericin B + flucytosine (induction 2 weeks) then fluconazole consolidation x8 weeks, then maintenance fluconazole until CD4 >200 on ART','Cryptococcal meningitis: opening pressure often elevated (>30 cm H2O) — therapeutic LP to reduce ICP (remove 20-30 mL CSF). Serum and CSF cryptococcal antigen has high sensitivity. Delay ART 4-6 weeks after starting antifungal therapy (COAT trial: early ART increases mortality).',5,'analyze',['cryptococcal meningitis','amphotericin B','fluconazole','HIV','infectious disease']);
add('id-meningitis','What is viral (aseptic) meningitis and how is it managed?','Aseptic meningitis: lymphocytic CSF pleocytosis with negative bacterial cultures; most common causes: enteroviruses, HSV-2; treatment is supportive — start IV acyclovir empirically for HSV if encephalitis features','Enteroviral meningitis is most common in summer/fall. CSF PCR for enterovirus is diagnostic. HSV meningitis (HSV-2): may recur (Mollaret meningitis). IV acyclovir started empirically when HSV cannot be excluded, especially if encephalitis features (altered consciousness, focal deficits).',3,'apply',['viral meningitis','aseptic meningitis','enterovirus','HSV','acyclovir','infectious disease']);
add('id-meningitis','What are the clinical features of herpes simplex encephalitis (HSE)?','Fever, headache, altered mental status, focal neurological deficits, seizures; MRI shows temporal lobe involvement (T2/FLAIR hyperintensity); CSF PCR for HSV-1 is diagnostic','HSE is the most common cause of fatal sporadic encephalitis. HSV-1 causes temporal lobe encephalitis via retrograde neuronal spread from olfactory nerves. Empiric IV acyclovir 10 mg/kg q8h must be started immediately — do not wait for PCR results. Treatment duration: 14-21 days.',4,'analyze',['HSE','herpes simplex encephalitis','temporal lobe','acyclovir','PCR','infectious disease']);
add('id-meningitis','What are the meningococcal vaccine indications in Canada?','Routine immunization: meningococcal C conjugate at 12 months, Men ACWY at 12 years; high-risk groups: asplenia, complement deficiency, travel to endemic areas, lab workers, close contacts of cases','NACI (National Advisory Committee on Immunization) Canada recommends meningococcal ACWY vaccine for adolescents and at-risk groups. Meningococcal B vaccine (Bexsero or Trumenba) recommended for high-risk groups; not in routine schedule.',2,'recall',['meningococcal vaccine','NACI','immunization','meningitis prevention','infectious disease']);
add('id-meningitis','How is tuberculous meningitis (TBM) distinguished from other meningitides?','TBM: subacute onset (weeks), lymphocytic pleocytosis, low glucose, very high protein, CSF AFB smear low sensitivity, CSF Xpert MTB/RIF; CT/MRI: basilar meningeal enhancement, hydrocephalus, tuberculomas','TBM requires 4-drug anti-TB therapy (RIPE) for minimum 12 months. Dexamethasone reduces mortality and neurological complications in TBM. Hydrocephalus may require ventriculoperitoneal shunt. Prognosis depends on clinical grade at presentation.',4,'analyze',['tuberculous meningitis','TBM','CSF findings','anti-TB treatment','infectious disease']);

